SELECT id, organizer_user_id, title, subtitle, category_code, description, location_text, address, latitude, longitude, cover_url, capacity, fee_type, fee_amount, allow_waitlist, require_checkin, status, start_at, end_at, reminder_minutes, review_note FROM local_activity
status = #{status}
AND start_at <= NOW() AND end_at >= NOW()
AND start_at > NOW()
AND end_at < NOW()
ORDER BY created_at DESC LIMIT #{limit} OFFSET #{offset}

